    <style>
        :root {
            --primary: #10b981;
            --primary-hover: #059669;
            --primary-light: rgba(16, 185, 129, 0.1);
            --bg: #f8fafc;
            --card-bg: #ffffff;
            --text-main: #0f172a;
            --text-muted: #64748b;
            --border: #e2e8f0;
            --border-hover: #cbd5e1;
            --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
            --shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05), 0 2px 4px -2px rgba(0, 0, 0, 0.05);
            --shadow-md: 0 10px 15px -3px rgba(0, 0, 0, 0.05), 0 4px 6px -4px rgba(0, 0, 0, 0.05);
        }
        body.dark-mode {
            --primary: #10b981;
            --primary-hover: #059669;
            --primary-light: rgba(16, 185, 129, 0.15);
            --bg: #0f172a;
            --card-bg: #1e293b;
            --text-main: #f8fafc;
            --text-muted: #94a3b8;
            --border: #334155;
            --border-hover: #475569;
        }
        body {
            font-family: 'Inter', sans-serif;
            background-color: var(--bg);
            color: var(--text-main);
            min-height: 100vh;
            transition: background-color 0.3s, color 0.3s;
        }
        .navbar-custom {
            background-color: rgba(255, 255, 255, 0.8) !important;
            backdrop-filter: blur(12px);
            -webkit-backdrop-filter: blur(12px);
            border-bottom: 1px solid var(--border);
            position: sticky;
            top: 0;
            z-index: 1020;
            transition: background-color 0.3s, border-color 0.3s;
        }
        body.dark-mode .navbar-custom {
            background-color: rgba(30, 41, 59, 0.8) !important;
        }
        .navbar-brand {
            font-weight: 700;
            color: var(--primary) !important;
            font-size: 1.4rem;
        }
        .card-custom {
            border: 1px solid var(--border) !important;
            border-radius: 16px;
            box-shadow: var(--shadow) !important;
            background: var(--card-bg) !important;
            transition: transform 0.3s cubic-bezier(0.4, 0, 0.2, 1), box-shadow 0.3s cubic-bezier(0.4, 0, 0.2, 1), border-color 0.3s, background-color 0.3s;
        }
        .card-custom:hover {
            transform: translateY(-2px);
            box-shadow: var(--shadow-md) !important;
            border-color: var(--border-hover) !important;
        }
        .month-header {
            font-size: 2.2rem;
            font-weight: 700;
            color: var(--text-main);
        }
        .btn-green-outline {
            color: var(--primary);
            border: 2px solid var(--primary);
            font-weight: 600;
            border-radius: 10px;
            transition: all 0.2s ease;
            background: transparent;
            padding: 0.5rem 1.25rem;
        }
        .btn-green-outline:hover {
            background-color: var(--primary);
            border-color: var(--primary);
            color: #ffffff;
            box-shadow: 0 4px 12px var(--primary-light);
        }
        body.dark-mode .btn-green-outline:hover {
            color: #0f172a;
        }
        .btn-green {
            background-color: var(--primary);
            border-color: var(--primary);
            color: white;
            font-weight: 600;
            border-radius: 10px;
            padding: 0.5rem 1.25rem;
            transition: all 0.2s ease;
        }
        .btn-green:hover {
            background-color: var(--primary-hover);
            border-color: var(--primary-hover);
            color: white;
            box-shadow: 0 4px 12px var(--primary-light);
        }
        .table-container {
            overflow-x: auto;
            border-radius: 12px;
            border: 1px solid var(--border);
            background-color: var(--card-bg);
        }
        .habit-table {
            margin-bottom: 0;
            background-color: var(--card-bg);
            color: var(--text-main);
        }
        .habit-table th {
            background-color: var(--bg);
            color: var(--text-muted);
            font-weight: 600;
            font-size: 0.85rem;
            text-align: center;
            border-bottom: 2px solid var(--border);
            padding: 0.75rem 0.5rem;
        }
        .habit-table th.habit-name-col {
            text-align: left;
            padding-left: 1.5rem;
            min-width: 200px;
        }
        .habit-table td {
            vertical-align: middle;
            text-align: center;
            padding: 0.6rem 0.4rem;
            border-bottom: 1px solid var(--border);
        }
        .habit-table td.habit-name-col {
            text-align: left;
            padding-left: 1.5rem;
            font-weight: 600;
            font-size: 0.95rem;
        }
        .habit-checkbox {
            width: 22px;
            height: 22px;
            border-radius: 6px;
            border: 2px solid var(--border-hover);
            cursor: pointer;
            appearance: none;
            -webkit-appearance: none;
            display: inline-block;
            outline: none;
            position: relative;
            background-color: var(--card-bg);
            transition: all 0.15s ease-in-out;
        }
        .habit-checkbox:checked {
            background-color: var(--primary);
            border-color: var(--primary);
        }
        .habit-checkbox:checked::after {
            content: "\F26B";
            font-family: "bootstrap-icons";
            font-weight: 900;
            color: white;
            font-size: 14px;
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
        }
        .habit-checkbox:disabled {
            background-color: var(--border);
            cursor: not-allowed;
            border-color: var(--border);
        }
        .status-toast {
            position: fixed;
            bottom: 20px;
            right: 20px;
            z-index: 1050;
            display: none;
        }
        .today-col {
            background-color: var(--primary-light) !important;
            border-left: 1px dashed var(--primary) !important;
            border-right: 1px dashed var(--primary) !important;
        }
        .live-clock-container {
            border: 1px solid var(--border);
            border-radius: 12px;
            background-color: var(--card-bg);
        }
        .fade-in-up {
            animation: fadeInUp 0.4s ease-out forwards;
        }
        @keyframes fadeInUp {
            from {
                opacity: 0;
                transform: translateY(15px);
            }
            to {
                opacity: 1;
                transform: translateY(0);
            }
        }
        .chart-box {
            position: relative;
            height: 120px;
            width: 100%;
        }
        .chart-center-label {
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            font-size: 1.5rem;
            font-weight: 800;
            color: var(--text-main);
        }
        /* Skeleton Shimmer Loading Utilities */
        .skeleton {
            background-color: var(--border);
            background-image: linear-gradient(
                90deg,
                rgba(255, 255, 255, 0) 0%,
                rgba(255, 255, 255, 0.4) 50%,
                rgba(255, 255, 255, 0) 100%
            );
            background-size: 200px 100%;
            background-repeat: no-repeat;
            animation: shimmer 1.5s infinite;
        }
        @keyframes shimmer {
            0% {
                background-position: -200px 0;
            }
            100% {
                background-position: calc(200px + 100%) 0;
            }
        }
        .fab {
            position: fixed;
            bottom: 30px;
            right: 30px;
            width: 60px;
            height: 60px;
            border-radius: 50%;
            background-color: var(--primary);
            color: white;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 24px;
            box-shadow: 0 4px 12px var(--primary-light);
            cursor: pointer;
            z-index: 1000;
            transition: transform 0.2s, background-color 0.2s, box-shadow 0.2s;
            text-decoration: none;
        }
        .fab:hover {
            transform: scale(1.1);
            background-color: var(--primary-hover);
            color: white;
            box-shadow: 0 6px 16px rgba(16, 185, 129, 0.4);
        }

        /* Modal custom dark overrides */
        body.dark-mode .modal-content {
            background-color: var(--card-bg) !important;
            border-color: var(--border) !important;
            color: var(--text-main) !important;
        }
        body.dark-mode .modal-header, body.dark-mode .modal-footer {
            border-color: var(--border) !important;
        }
        body.dark-mode .modal-header .btn-close {
            filter: invert(1) grayscale(100%) brightness(200%);
        }

        /* Calendar specific dark overrides */
        body.dark-mode .calendar-grid .day-cell.header-cell {
            color: var(--text-muted) !important;
        }
        body.dark-mode .calendar-grid .day-cell.day-border {
            border-color: var(--border) !important;
        }
        body.dark-mode .calendar-grid .day-cell:not(.empty-cell):hover {
            background-color: var(--border-hover) !important;
        }
        body.dark-mode .calendar-grid .day-cell.today-cell {
            background-color: var(--primary-light) !important;
            border-color: var(--primary) !important;
        }
    </style>
</head>
