<!-- Scripts -->
<script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js"></script>
<!-- Chart.js -->
<script src="https://cdn.jsdelivr.net/npm/chart.js"></script>

<script>
    function saveProgress(checkbox) {
        const habitId = checkbox.getAttribute('data-habit-id');
        const date = checkbox.getAttribute('data-date');
        const completed = checkbox.checked;

        const csrfToken = document.querySelector("meta[name='_csrf']").getAttribute("content");
        const csrfHeader = document.querySelector("meta[name='_csrf_header']").getAttribute("content");

        const url = completed ? '/habit/check' : '/habit/uncheck';

        const params = new URLSearchParams();
        params.append('habitId', habitId);
        params.append('date', date);

        checkbox.disabled = true;

        fetch(url, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/x-www-form-urlencoded',
                [csrfHeader]: csrfToken
            },
            body: params
        })
        .then(response => {
            if (!response.ok) {
                return response.json().then(data => {
                    throw new Error(data.message || 'HTTP error ' + response.status);
                });
            }
            return response.json();
        })
        .then(data => {
            checkbox.disabled = false;
            showToast();
            // Reload page to automatically refresh progress charts and stats cards
            setTimeout(() => {
                window.location.reload();
            }, 500);
        })
        .catch(error => {
            console.error('Error auto-saving habit:', error);
            checkbox.checked = !completed;
            checkbox.disabled = false;
            showErrorToast(error.message || "Failed to save progress. Only today's date can be edited.");
        });
    }

    function showToast() {
        const toastEl = document.querySelector('.status-toast');
        toastEl.style.display = 'block';
        setTimeout(() => {
            toastEl.style.display = 'none';
        }, 1500);
    }

    function showErrorToast(msg) {
        const toastEl = document.querySelector('.error-toast');
        document.getElementById('error-toast-msg').innerText = msg;
        toastEl.style.display = 'block';
        setTimeout(() => {
            toastEl.style.display = 'none';
        }, 3000);
    }

    // Set loaded server day and month in IST using comment inlining to prevent syntax errors
    window.loadedDay = "08";
    window.loadedMonth = "07";

    function updateClock() {
        const now = new Date();

        // Browser timezone formatting options targeting Asia/Kolkata
        const weekday = now.toLocaleDateString('en-US', { timeZone: 'Asia/Kolkata', weekday: 'long' });
        const day = now.toLocaleDateString('en-US', { timeZone: 'Asia/Kolkata', day: '2-digit' });
        const month = now.toLocaleDateString('en-US', { timeZone: 'Asia/Kolkata', month: 'long' });
        const year = now.toLocaleDateString('en-US', { timeZone: 'Asia/Kolkata', year: 'numeric' });

        // Output format: Day on top, Date below
        const dateHtml = `${weekday}<br/>${day} ${month} ${year}`;

        const timeString = now.toLocaleTimeString('en-US', {
            timeZone: 'Asia/Kolkata',
            hour: '2-digit',
            minute: '2-digit',
            second: '2-digit',
            hour12: true
        }) + ' IST';

        document.getElementById('live-date').innerHTML = dateHtml;
        document.getElementById('live-time').innerText = timeString;

        // Midnight detection and dynamic refresh
        const currentDay = now.toLocaleDateString('en-US', { timeZone: 'Asia/Kolkata', day: '2-digit' });
        const currentMonth = now.toLocaleDateString('en-US', { timeZone: 'Asia/Kolkata', month: '2-digit' });

        if (window.loadedDay && currentDay !== window.loadedDay) {
            window.loadedDay = currentDay;
            // Refresh dashboard if month changes
            if (window.loadedMonth && currentMonth !== window.loadedMonth) {
                window.location.reload();
            }
        }
    }

    // Init live clock
    setInterval(updateClock, 1000);
    updateClock();

    // Auto-scroll to today's column on load
    window.addEventListener('DOMContentLoaded', () => {
        setTimeout(() => {
            const todayCol = document.querySelector('.today-col');
            if (todayCol) {
                todayCol.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
            }
        }, 300);
    });

    // ----------------------------------------------------
    // CHART.JS CONFIGURATION (DOUGHNUT CHARTS)
    // ----------------------------------------------------
    const overallVal = 0;
    const todayVal = 0;
    const weeklyVal = 0;
    const monthlyVal = 0;

    if (!window.myCharts) {
        window.myCharts = {};
    }

    function createDoughnutChart(canvasId, value) {
        // Destroy old chart before creating new one to prevent memory leaks and duplicates
        if (window.myCharts[canvasId]) {
            window.myCharts[canvasId].destroy();
        }

        const ctx = document.getElementById(canvasId).getContext('2d');
        window.myCharts[canvasId] = new Chart(ctx, {
            type: 'doughnut',
            data: {
                labels: ['Completed', 'Remaining'],
                datasets: [{
                    data: [value, 100 - value],
                    backgroundColor: ['#22c55e', '#ecf0f1'],
                    borderWidth: 0,
                    borderRadius: 10,
                    borderAlign: 'inner'
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                cutout: '75%', // Thickness
                animation: {
                    duration: 1200,
                    easing: 'easeOutQuart'
                },
                plugins: {
                    legend: { display: false },
                    tooltip: {
                        enabled: true,
                        callbacks: {
                            label: function(context) {
                                return ' ' + context.label + ': ' + context.raw + '%';
                            }
                        }
                    }
                }
            }
        });
    }

    createDoughnutChart('overallChart', overallVal);
    createDoughnutChart('todayChart', todayVal);
    createDoughnutChart('weeklyChart', weeklyVal);
    createDoughnutChart('monthlyChart', monthlyVal);
</script>
</body>
</html>

